#include <stdio.h>

int main(void) {
    int x = 10;
    int *p = &x;

    printf("x  = %d\n", x);
    printf("*p = %d   (same value — p points at x)\n", *p);

    *p = 42;
    printf("after *p = 42, x = %d\n", x);

    return 0;
}

#include <stdio.h>

int main(void) {
    int x = 10;
    int *p = &x;

    /* Bug: %d expects an int, but p is a pointer (an address).
       You wanted the value *at* x, which is *p — not p itself. */
    printf("value at x: %d\n", p);

    return 0;
}
